"""Polish Validator — validates canonical merged TTS polish against canonical screenplay.

Detects:
- scene identity/order mismatches
- narration_original preservation failures
- eaten words
- suspicious additions
- missing/empty narration_tts

100% deterministic, no LLM.
"""

from __future__ import annotations

import re
from collections import Counter
from typing import Any


LEGACY_ORIGINAL_KEYS = ("original",)
LEGACY_TTS_KEYS = ("polished",)


def validate_polish(
    screenplay: list[dict[str, Any]],
    polished: list[dict[str, Any]],
) -> dict[str, Any]:
    """Validate canonical merged polish against canonical screenplay.

    Args:
        screenplay: Canonical screenplay scenes with `scene_id` and `narration_original`.
        polished: Canonical merged polish scenes with `scene_id`, `narration_original`,
            `narration_tts` (legacy `original/polished` tolerated for compatibility).

    Returns:
        Structured deterministic validation result.
    """
    eaten_words: list[dict[str, Any]] = []
    added_words: list[dict[str, Any]] = []
    acceptable_changes: list[dict[str, Any]] = []
    dangerous_changes: list[dict[str, Any]] = []
    affected_scenes: list[str] = []
    warnings: list[dict[str, Any]] = []

    screenplay_map = {
        scene.get("scene_id"): scene
        for scene in screenplay
        if isinstance(scene, dict) and scene.get("scene_id")
    }
    screenplay_order = [scene.get("scene_id") for scene in screenplay if isinstance(scene, dict) and scene.get("scene_id")]

    polished_map = {
        scene.get("scene_id"): scene
        for scene in polished
        if isinstance(scene, dict) and scene.get("scene_id")
    }
    polished_order = [scene.get("scene_id") for scene in polished if isinstance(scene, dict) and scene.get("scene_id")]

    # Scene order must be preserved exactly in canonical merged artifact
    if screenplay_order != polished_order:
        dangerous_changes.append({
            "code": "scene_order_mismatch",
            "message": "Canonical polish scene order does not match screenplay order",
        })
        for scene_id in _ordered_union(screenplay_order, polished_order):
            if scene_id not in affected_scenes:
                affected_scenes.append(scene_id)

    # Missing/extra scene identity mismatches
    for scene_id in screenplay_order:
        if scene_id not in polished_map:
            dangerous_changes.append({
                "code": "missing_polish_scene",
                "scene": scene_id,
                "message": f"Missing polish output for screenplay scene {scene_id}",
            })
            if scene_id not in affected_scenes:
                affected_scenes.append(scene_id)

    for scene_id in polished_order:
        if scene_id not in screenplay_map:
            dangerous_changes.append({
                "code": "unexpected_polish_scene",
                "scene": scene_id,
                "message": f"Polish output contains unexpected scene {scene_id}",
            })
            if scene_id not in affected_scenes:
                affected_scenes.append(scene_id)

    # Validate only aligned scenes
    for scene_id in screenplay_order:
        scene_sp = screenplay_map.get(scene_id)
        scene_pol = polished_map.get(scene_id)
        if not scene_sp or not scene_pol:
            continue

        original = str(scene_sp.get("narration_original", ""))
        polished_original = _get_original_reference(scene_pol)
        narration_tts = _get_narration_tts(scene_pol)

        if polished_original != original:
            dangerous_changes.append({
                "code": "narration_original_mismatch",
                "scene": scene_id,
                "message": "Polish layer does not preserve narration_original exactly",
            })
            _add_affected(affected_scenes, scene_id)

        if not narration_tts.strip():
            dangerous_changes.append({
                "code": "empty_narration_tts",
                "scene": scene_id,
                "message": "Polish layer has empty narration_tts",
            })
            _add_affected(affected_scenes, scene_id)
            continue

        orig_words = _tokenize(original)
        tts_words = _tokenize(narration_tts)
        orig_counter = Counter(orig_words)
        tts_counter = Counter(tts_words)

        scene_eaten = []
        for word, count in orig_counter.items():
            if tts_counter.get(word, 0) < count and len(word) > 2:
                diff = count - tts_counter.get(word, 0)
                scene_eaten.append({"word": word, "count": diff, "scene": scene_id})

        scene_added = []
        for word, count in tts_counter.items():
            if orig_counter.get(word, 0) < count and len(word) > 2:
                diff = count - orig_counter.get(word, 0)
                scene_added.append({"word": word, "count": diff, "scene": scene_id})

        changes = scene_pol.get("changes", [])
        for change in changes if isinstance(changes, list) else []:
            change_text = str(change)
            change_entry = {"scene": scene_id, "change": change_text}
            if any(kw in change_text.lower() for kw in ["expand", "abbrevi", "accent", "acronym", "ordinal", "unit"]):
                acceptable_changes.append(change_entry)
            else:
                warnings.append({
                    "code": "uncategorized_change_note",
                    "scene": scene_id,
                    "message": f"Change note not auto-classified: {change_text}",
                })

        if scene_eaten:
            eaten_words.extend(scene_eaten)
            _add_affected(affected_scenes, scene_id)

        if scene_added:
            added_words.extend(scene_added)
            _add_affected(affected_scenes, scene_id)

    # Conservative validity rule:
    # - no dangerous structural/identity mismatches
    # - no significant eaten-word failures
    significant_eaten = [item for item in eaten_words if item.get("count", 0) > 0]
    valid = len(dangerous_changes) == 0 and len(significant_eaten) == 0

    return {
        "valid": valid,
        "eaten_words": eaten_words[:20],
        "added_words": added_words[:20],
        "acceptable_changes": acceptable_changes[:20],
        "dangerous_changes": dangerous_changes[:20],
        "affected_scenes": affected_scenes,
        "warnings": warnings[:20],
        "scene_count": len(screenplay_order),
        "details": (
            f"{len(eaten_words)} eaten, {len(added_words)} added, "
            f"{len(dangerous_changes)} dangerous, {len(acceptable_changes)} acceptable changes"
        ),
    }


def _get_original_reference(scene: dict[str, Any]) -> str:
    if "narration_original" in scene:
        return str(scene.get("narration_original", ""))
    for key in LEGACY_ORIGINAL_KEYS:
        if key in scene:
            return str(scene.get(key, ""))
    return ""


def _get_narration_tts(scene: dict[str, Any]) -> str:
    if "narration_tts" in scene:
        return str(scene.get("narration_tts", ""))
    for key in LEGACY_TTS_KEYS:
        if key in scene:
            return str(scene.get(key, ""))
    return ""


def _ordered_union(a: list[str], b: list[str]) -> list[str]:
    seen: set[str] = set()
    result: list[str] = []
    for item in a + b:
        if item and item not in seen:
            seen.add(item)
            result.append(item)
    return result


def _add_affected(affected_scenes: list[str], scene_id: str) -> None:
    if scene_id not in affected_scenes:
        affected_scenes.append(scene_id)


def _tokenize(text: str) -> list[str]:
    text = text.lower()
    words = re.findall(r"[\w']+", text)
    return [w for w in words if len(w) > 0]

