def _coverage_percentage(original_words: list[str], screenplay_words: list[str]) -> float:
    if not original_words:
        return 100.0
    original_counter = Counter(original_words)
    screenplay_counter = Counter(screenplay_words)
    matched = 0
    for word, count in original_counter.items():
        matched += min(count, screenplay_counter.get(word, 0))
    return (matched / len(original_words)) * 100


