"""Scene Bible Schema Validator — validates S1-stage structure of scene_bible.json.

Checks:
- required top-level fields
- required-at-S1 scene fields
- reserved downstream fields presence
- duplicate scene IDs
- scene_count consistency

100% deterministic.
"""

from __future__ import annotations

from typing import Any


REQUIRED_TOP_FIELDS = [
    "version",
    "job_id",
    "account",
    "language",
    "scene_count",
    "scenes",
]

REQUIRED_SCENE_FIELDS_S1 = [
    "scene_id",
    "narration",
    "narration_original",
    "narration_tts",
    "scene_title",
    "scene_summary",
    "narrative_function",
    "sectors_contributed",
]

RESERVED_SCENE_FIELDS = [
    "audio_clip",
    "duration_actual",
    "word_timestamps",
    "entities",
    "assets",
    "visual_brief",
    "visual_direction",
    "mood",
    "composition",
]


def validate_scene_bible_schema(bible: dict[str, Any]) -> dict[str, Any]:
    """Validate S1-stage scene bible structure."""
    errors: list[dict[str, Any]] = []
    warnings: list[dict[str, Any]] = []

    for field in REQUIRED_TOP_FIELDS:
        if field not in bible:
            errors.append({
                "code": "missing_top_field",
                "field": field,
                "message": f"Missing required field: {field}",
            })

    if errors:
        return {"valid": False, "errors": errors, "warnings": warnings}

    scenes = bible.get("scenes", [])
    if not isinstance(scenes, list):
        errors.append({
            "code": "invalid_scenes_type",
            "field": "scenes",
            "message": "scenes must be a list",
        })
        return {"valid": False, "errors": errors, "warnings": warnings}

    if len(scenes) == 0:
        errors.append({
            "code": "empty_scenes",
            "field": "scenes",
            "message": "scenes list is empty",
        })
        return {"valid": False, "errors": errors, "warnings": warnings}

    if bible.get("scene_count") != len(scenes):
        warnings.append({
            "code": "scene_count_mismatch",
            "message": f"scene_count={bible.get('scene_count')} but {len(scenes)} scenes in list",
        })

    seen_scene_ids: set[str] = set()
    for i, scene in enumerate(scenes):
        scene_id = scene.get("scene_id", f"scene_{i}")

        for field in REQUIRED_SCENE_FIELDS_S1:
            if field not in scene:
                errors.append({
                    "code": "missing_scene_field",
                    "field": f"scenes[{i}].{field}",
                    "scene_id": scene_id,
                    "message": f"Scene {scene_id} missing required S1 field: {field}",
                })

        narration = str(scene.get("narration", ""))
        narration_original = str(scene.get("narration_original", ""))
        narration_tts = str(scene.get("narration_tts", ""))

        if not narration.strip():
            errors.append({
                "code": "empty_narration",
                "field": f"scenes[{i}].narration",
                "scene_id": scene_id,
                "message": f"Scene {scene_id} has empty narration",
            })

        if not narration_original.strip():
            errors.append({
                "code": "empty_narration_original",
                "field": f"scenes[{i}].narration_original",
                "scene_id": scene_id,
                "message": f"Scene {scene_id} has empty narration_original",
            })

        if not narration_tts.strip():
            errors.append({
                "code": "empty_narration_tts",
                "field": f"scenes[{i}].narration_tts",
                "scene_id": scene_id,
                "message": f"Scene {scene_id} has empty narration_tts",
            })

        if narration and narration_tts and narration != narration_tts:
            warnings.append({
                "code": "narration_field_mismatch",
                "field": f"scenes[{i}].narration",
                "scene_id": scene_id,
                "message": f"Scene {scene_id} narration differs from narration_tts; compatibility field should normally mirror narration_tts",
            })

        for field in RESERVED_SCENE_FIELDS:
            if field not in scene:
                warnings.append({
                    "code": "missing_reserved_field",
                    "field": f"scenes[{i}].{field}",
                    "scene_id": scene_id,
                    "message": f"Scene {scene_id} missing reserved field: {field}",
                })

        if scene_id in seen_scene_ids:
            errors.append({
                "code": "duplicate_scene_id",
                "field": "scene_id",
                "message": f"Duplicate scene_id: {scene_id}",
            })
        seen_scene_ids.add(scene_id)

    return {
        "valid": len(errors) == 0,
        "errors": errors,
        "warnings": warnings,
        "scene_count": len(scenes),
    }
